document.addEventListener('DOMContentLoaded',()=>{const e=document.getElementById('backToTop'),t=document.getElementById('progressBar');function n(){const e=window.pageYOffset,n=document.documentElement.scrollHeight-window.innerHeight;t&&(t.style.width=(e/n)*100+'%'),e>300?e.classList.add('show'):e.classList.remove('show')}e&&(window.addEventListener('scroll',n,{passive:!0}),e.addEventListener('click',()=>{window.scrollTo({top:0,behavior:'smooth'})}),n())}),document.addEventListener('DOMContentLoaded',()=>{document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener('click',t=>{t.preventDefault();const n=e.getAttribute('href'),r=document.querySelector(n);r&&(r.focus(),r.scrollIntoView({behavior:'smooth'}))})})});